 12→pub struct SdzFirestoreSpotRepository {
 13→    project_id: String,
 14→    bearer_token: String,
 15→    http: Client,
 16→}
 17→
 18→impl SdzFirestoreSpotRepository {
 19→    pub fn new(project_id: String, bearer_token: String) -> Result<Self, SdzApiError> {
 20→        let http = Client::builder().build().map_err(|e| {
 21→            tracing::error!("Failed to build reqwest client: {:?}", e);
 22→            SdzApiError::Internal
 23→        })?;
 24→        Ok(Self {
 25→            project_id,
 26→            bearer_token,
 27→            http,
 28→        })
 29→    }
 30→
 31→    async fn upsert_document(&self, spot: &SdzSpot) -> Result<(), SdzApiError> {
 32→        let url = format!(
 33→            "https://firestore.googleapis.com/v1/projects/{}/databases/(default)/documents/spots/{}",
 34→            self.project_id, spot.sdz_spot_id
 35→        );
 36→
 37→        let body = build_firestore_doc(spot)?;
 38→
 39→        let resp = self
 40→            .http
 41→            .patch(url)
 42→            .bearer_auth(&self.bearer_token)
 43→            .json(&body)
 44→            .send()
 45→            .await
 46→            .map_err(|e| {
 47→                tracing::error!("Firestore request error: {:?}", e);
 48→                SdzApiError::Internal
 49→            })?;
 50→
 51→        map_status(resp.status(), resp.text().await).map(|_| ())
 52→    }
 53→
 54→    async fn get_document(&self, spot_id: &str) -> Result<Option<FirestoreSpotDoc>, SdzApiError> {
 55→        let url = format!(
 56→            "https://firestore.googleapis.com/v1/projects/{}/databases/(default)/documents/spots/{}",
 57→            self.project_id, spot_id
 58→        );
 59→        let resp = self
 60→            .http
 61→            .get(url)
 62→            .bearer_auth(&self.bearer_token)
 63→            .send()
 64→            .await
 65→            .map_err(|e| {
 66→                tracing::error!("Firestore request error: {:?}", e);
 67→                SdzApiError::Internal
 68→            })?;
 69→
 70→        match resp.status() {
 71→            reqwest::StatusCode::OK => {
 72→                let doc = resp.json::<FirestoreSpotDoc>().await.map_err(|e| {
 73→                    tracing::error!("Failed to parse Firestore response: {:?}", e);
 74→                    SdzApiError::Internal
 75→                })?;
 76→                Ok(Some(doc))
 77→            }
 78→            reqwest::StatusCode::NOT_FOUND => Ok(None),
 79→            code => {
 80→                let body = resp.text().await.unwrap_or_default();
 81→                tracing::error!("Firestore unexpected status: {} body: {}", code, body);
 82→                Err(SdzApiError::Internal)
 83→            }
 84→        }
 85→    }
 86→}
