131→fn build_state() -> SdzAppState {
132→    let storage_repo: Arc<dyn SdzStorageRepository> = build_storage_repo();
133→    // 環境変数が整っていればFirestore実装を採用
134→    if std::env::var("SDZ_USE_FIRESTORE").ok().as_deref() == Some("1") {
135→        if let (Ok(project_id), Ok(token)) = (
