180→fn build_storage_repo() -> Arc<dyn SdzStorageRepository> {
181→    let bucket = std::env::var("SDZ_STORAGE_BUCKET").ok();
182→    let service_account = std::env::var("SDZ_STORAGE_SERVICE_ACCOUNT_EMAIL").ok();
183→    let expires = std::env::var("SDZ_STORAGE_SIGNED_URL_EXPIRES_SECS")
184→        .ok()
185→        .and_then(|v| v.parse::<u32>().ok())
186→        .unwrap_or(900);
187→
188→    if let (Some(bucket), Some(service_account)) = (bucket, service_account) {
189→        match SdzStorageSignedUrlRepository::new(bucket, service_account, expires) {
190→            Ok(repo) => return Arc::new(repo),
191→            Err(_) => tracing::warn!("Failed to init storage repo, falling back to disabled"),
192→        }
193→    } else {
194→        tracing::warn!("Storage config missing, upload-url will be disabled");
195→    }
196→
197→    Arc::new(SdzDisabledStorageRepository)
198→}
