 50→#[derive(Debug, Deserialize)]
 51→#[allow(dead_code)]
 52→struct FirebaseClaims {
 53→    #[serde(default)]
 54→    sub: String,
 55→    #[serde(default)]
 56→    user_id: String,
 57→    #[serde(default)]
 58→    aud: String,
 59→    #[serde(default)]
 60→    iss: String,
 61→    #[serde(default)]
 62→    exp: u64,
 63→    #[serde(default)]
 64→    iat: Option<u64>,
 65→}
 66→
 67→impl FirebaseClaims {
 68→    fn sdz_user_id(&self) -> String {
 69→        if !self.user_id.is_empty() {
 70→            self.user_id.clone()
 71→        } else {
 72→            self.sub.clone()
 73→        }
 74→    }
