 76→
 77→static HTTP_CLIENT: Lazy<Client> = Lazy::new(|| Client::builder().build().expect("client"));
 78→
 79→async fn fetch_jwks() -> Result<HashMap<String, String>, SdzApiError> {
 80→    // Firebase/Identity Platformの公開鍵（kid->x509 cert）エンドポイント
 81→    // 参考: https://firebase.google.com/docs/auth/admin/verify-id-tokens#retrieve_public_keys
 82→    let jwks_url =
 83→        "https://www.googleapis.com/robot/v1/metadata/x509/securetoken@system.gserviceaccount.com";
 84→    let resp = HTTP_CLIENT
 85→        .get(jwks_url)
 86→        .send()
 87→        .await
 88→        .map_err(|e| {
 89→            tracing::error!("Failed to fetch JWKS: {:?}", e);
 90→            SdzApiError::Internal
 91→        })?
 92→        .json::<HashMap<String, String>>()
 93→        .await
 94→        .map_err(|e| {
 95→            tracing::error!("Failed to parse JWKS: {:?}", e);
 96→            SdzApiError::Internal
 97→        })?;
 98→    Ok(resp)
 99→}
100→
101→async fn verify_firebase_token(token: &str) -> Result<FirebaseClaims, SdzApiError> {
102→    let header = decode_header(token).map_err(|e| {
103→        tracing::error!("Failed to decode JWT header: {:?}", e);
104→        SdzApiError::Unauthorized
105→    })?;
106→    let kid = header.kid.ok_or_else(|| {
107→        tracing::error!("JWT header missing kid");
108→        SdzApiError::Unauthorized
109→    })?;
110→
111→    let jwks = fetch_jwks().await?;
112→    let pem = jwks.get(&kid).ok_or_else(|| {
113→        tracing::error!("kid not found in JWKS: {}", kid);
114→        SdzApiError::Unauthorized
115→    })?;
116→    let decoding_key = DecodingKey::from_rsa_pem(pem.as_bytes()).map_err(|e| {
117→        tracing::error!("Failed to build decoding key: {:?}", e);
118→        SdzApiError::Unauthorized
119→    })?;
120→
121→    let project_id = std::env::var("SDZ_AUTH_PROJECT_ID").map_err(|e| {
122→        tracing::error!("SDZ_AUTH_PROJECT_ID not set: {:?}", e);
123→        SdzApiError::Internal
124→    })?;
125→    let issuer = format!("https://securetoken.google.com/{}", project_id);
126→
127→    let mut validation = Validation::new(Algorithm::RS256);
128→    validation.set_required_spec_claims(&["exp", "iss", "aud"]);
129→    validation.set_issuer(&[issuer]);
130→    validation.set_audience(&[project_id]);
131→    validation.validate_exp = true;
132→
133→    let data = decode::<FirebaseClaims>(token, &decoding_key, &validation).map_err(|e| {
134→        tracing::error!("JWT decode/validate error: {:?}", e);
135→        SdzApiError::Unauthorized
136→    })?;
137→
138→    Ok(data.claims)
139→}
