 17→const SDZ_STORAGE_HOST: &str = "storage.googleapis.com";
 18→const SDZ_GCS_ALGORITHM: &str = "GOOG4-RSA-SHA256";
 19→
 20→pub struct SdzStorageSignedUrlRepository {
 21→    sdz_bucket: String,
 22→    sdz_service_account_email: String,
 23→    sdz_expires_in: u32,
 24→    http: Client,
 25→}
 26→
 27→impl SdzStorageSignedUrlRepository {
 28→    pub fn new(
 29→        sdz_bucket: String,
 30→        sdz_service_account_email: String,
 31→        sdz_expires_in: u32,
 32→    ) -> Result<Self, SdzApiError> {
 33→        let http = Client::builder().build().map_err(|e| {
 34→            tracing::error!("Failed to build reqwest client: {:?}", e);
 35→            SdzApiError::Internal
 36→        })?;
 37→        Ok(Self {
 38→            sdz_bucket,
 39→            sdz_service_account_email,
 40→            sdz_expires_in,
 41→            http,
 42→        })
 43→    }
 44→
 45→    async fn fetch_access_token(&self) -> Result<String, SdzApiError> {
 46→        if let Ok(token) = std::env::var("SDZ_STORAGE_SIGNING_TOKEN") {
 47→            return Ok(token);
 48→        }
 49→        if let Ok(token) = std::env::var("SDZ_FIRESTORE_TOKEN") {
 50→            return Ok(token);
 51→        }
 52→
 53→        let metadata_url = "http://metadata.google.internal/computeMetadata/v1/instance/service-accounts/default/token";
 54→        let resp = self
 55→            .http
 56→            .get(metadata_url)
 57→            .header("Metadata-Flavor", "Google")
 58→            .send()
 59→            .await
 60→            .map_err(|e| {
 61→                tracing::error!("Failed to fetch metadata token: {:?}", e);
 62→                SdzApiError::Internal
 63→            })?;
 64→
 65→        if !resp.status().is_success() {
 66→            let body = resp.text().await.unwrap_or_default();
 67→            tracing::error!("Metadata token error: {}", body);
 68→            return Err(SdzApiError::Internal);
 69→        }
 70→
 71→        let token = resp.json::<SdzMetadataToken>().await.map_err(|e| {
 72→            tracing::error!("Failed to parse metadata token: {:?}", e);
 73→            SdzApiError::Internal
 74→        })?;
 75→
 76→        Ok(token.access_token)
 77→    }
 78→
 79→    async fn sign_blob(&self, access_token: &str, payload: &str) -> Result<String, SdzApiError> {
 80→        let url = format!(
 81→            "https://iamcredentials.googleapis.com/v1/projects/-/serviceAccounts/{}:signBlob",
 82→            self.sdz_service_account_email
 83→        );
 84→
 85→        let req = SdzSignBlobRequest {
 86→            payload: general_purpose::STANDARD.encode(payload.as_bytes()),
 87→        };
 88→
 89→        let resp = self
 90→            .http
 91→            .post(url)
 92→            .bearer_auth(access_token)
 93→            .json(&req)
 94→            .send()
 95→            .await
 96→            .map_err(|e| {
 97→                tracing::error!("signBlob request error: {:?}", e);
 98→                SdzApiError::Internal
 99→            })?;
100→
101→        if !resp.status().is_success() {
102→            let body = resp.text().await.unwrap_or_default();
103→            tracing::error!("signBlob error: {}", body);
104→            return Err(SdzApiError::Internal);
105→        }
106→
107→        let signed = resp.json::<SdzSignBlobResponse>().await.map_err(|e| {
108→            tracing::error!("Failed to parse signBlob response: {:?}", e);
109→            SdzApiError::Internal
110→        })?;
111→
112→        let signature_bytes = general_purpose::STANDARD
113→            .decode(signed.signed_blob.as_bytes())
114→            .map_err(|e| {
115→                tracing::error!("Failed to decode signedBlob: {:?}", e);
116→                SdzApiError::Internal
117→            })?;
118→
119→        Ok(signature_bytes.encode_hex())
120→    }
121→
122→    fn build_signed_url(
123→        &self,
124→        request: &SdzUploadUrlRequest,
125→        now: DateTime<Utc>,
126→        signature: &str,
127→    ) -> String {
128→        let timestamp = now.format("%Y%m%dT%H%M%SZ").to_string();
129→        let timestamp_query = timestamp.clone();
130→        let datestamp = now.format("%Y%m%d").to_string();
131→        let scope = format!("{}/auto/storage/goog4_request", datestamp);
132→        let credential = format!("{}/{}", self.sdz_service_account_email, scope);
133→
134→        let mut query_params = vec![
135→            (
136→                "X-Goog-Algorithm".to_string(),
137→                SDZ_GCS_ALGORITHM.to_string(),
138→            ),
139→            ("X-Goog-Credential".to_string(), credential),
140→            ("X-Goog-Date".to_string(), timestamp_query),
141→            (
142→                "X-Goog-Expires".to_string(),
143→                self.sdz_expires_in.to_string(),
144→            ),
145→            (
146→                "X-Goog-SignedHeaders".to_string(),
147→                "content-type;host".to_string(),
148→            ),
149→        ];
150→
151→        query_params.sort();
152→        let canonical_query = sdz_build_query(&query_params);
153→        let canonical_uri = sdz_build_canonical_uri(&self.sdz_bucket, &request.sdz_object_name);
154→
155→        format!(
156→            "https://{}{}?{}&X-Goog-Signature={}",
157→            SDZ_STORAGE_HOST, canonical_uri, canonical_query, signature
158→        )
159→    }
160→
161→    fn build_object_url(&self, object_name: &str) -> String {
162→        let encoded_path = sdz_encode_path(object_name);
163→        format!(
164→            "https://{}/{}/{}",
165→            SDZ_STORAGE_HOST, self.sdz_bucket, encoded_path
166→        )
167→    }
168→}
