170→#[async_trait]
171→impl SdzStorageRepository for SdzStorageSignedUrlRepository {
172→    async fn create_upload_url(
173→        &self,
174→        request: SdzUploadUrlRequest,
175→    ) -> Result<SdzUploadUrlResult, SdzApiError> {
176→        let now = Utc::now();
177→        let timestamp = now.format("%Y%m%dT%H%M%SZ").to_string();
178→        let timestamp_query = timestamp.clone();
179→        let datestamp = now.format("%Y%m%d").to_string();
180→        let scope = format!("{}/auto/storage/goog4_request", datestamp);
181→        let credential = format!("{}/{}", self.sdz_service_account_email, scope);
182→
183→        let mut query_params = vec![
184→            (
185→                "X-Goog-Algorithm".to_string(),
186→                SDZ_GCS_ALGORITHM.to_string(),
187→            ),
188→            ("X-Goog-Credential".to_string(), credential),
189→            ("X-Goog-Date".to_string(), timestamp_query),
190→            (
191→                "X-Goog-Expires".to_string(),
192→                self.sdz_expires_in.to_string(),
193→            ),
194→            (
195→                "X-Goog-SignedHeaders".to_string(),
196→                "content-type;host".to_string(),
197→            ),
198→        ];
199→
200→        query_params.sort();
201→        let canonical_query = sdz_build_query(&query_params);
202→        let canonical_uri = sdz_build_canonical_uri(&self.sdz_bucket, &request.sdz_object_name);
203→
204→        let canonical_headers = format!(
205→            "content-type:{}\nhost:{}\n",
206→            request.sdz_content_type, SDZ_STORAGE_HOST
207→        );
208→        let signed_headers = "content-type;host";
209→        let canonical_request = format!(
210→            "PUT\n{}\n{}\n{}\n{}\nUNSIGNED-PAYLOAD",
211→            canonical_uri, canonical_query, canonical_headers, signed_headers
212→        );
213→
214→        let canonical_hash = sdz_sha256_hex(&canonical_request);
215→        let string_to_sign = format!(
216→            "{}\n{}\n{}\n{}",
217→            SDZ_GCS_ALGORITHM, timestamp, scope, canonical_hash
218→        );
219→
220→        let access_token = self.fetch_access_token().await?;
221→        let signature = self.sign_blob(&access_token, &string_to_sign).await?;
222→        let upload_url = self.build_signed_url(&request, now, &signature);
223→        let object_url = self.build_object_url(&request.sdz_object_name);
224→
225→        let expires_at = sdz_to_jst(now + Duration::seconds(i64::from(self.sdz_expires_in)));
226→
227→        Ok(SdzUploadUrlResult {
228→            sdz_upload_url: upload_url,
229→            sdz_object_url: object_url,
230→            sdz_object_name: request.sdz_object_name,
231→            sdz_expires_at: expires_at,
232→        })
233→    }
234→}
