259→const SDZ_PATH_ENCODE_SET: &AsciiSet = &CONTROLS
260→    .add(b' ')
261→    .add(b'"')
262→    .add(b'<')
263→    .add(b'>')
264→    .add(b'`')
265→    .add(b'#')
266→    .add(b'?')
267→    .add(b'{')
268→    .add(b'}')
269→    .add(b'[')
270→    .add(b']')
271→    .add(b'%');
272→
273→const SDZ_QUERY_ENCODE_SET: &AsciiSet = &CONTROLS
274→    .add(b' ')
275→    .add(b'"')
276→    .add(b'#')
277→    .add(b'$')
278→    .add(b'%')
279→    .add(b'&')
280→    .add(b'\'')
281→    .add(b'(')
282→    .add(b')')
283→    .add(b'*')
284→    .add(b'+')
285→    .add(b',')
286→    .add(b'/')
287→    .add(b':')
288→    .add(b';')
289→    .add(b'<')
290→    .add(b'=')
291→    .add(b'>')
292→    .add(b'?')
293→    .add(b'@')
294→    .add(b'[')
295→    .add(b'\\')
296→    .add(b']')
297→    .add(b'^')
298→    .add(b'`')
299→    .add(b'{')
300→    .add(b'|')
301→    .add(b'}');
302→
303→fn sdz_encode_path(value: &str) -> String {
304→    value
305→        .split('/')
306→        .map(|segment| utf8_percent_encode(segment, SDZ_PATH_ENCODE_SET).to_string())
307→        .collect::<Vec<_>>()
308→        .join("/")
309→}
310→
311→fn sdz_encode_query(value: &str) -> String {
312→    utf8_percent_encode(value, SDZ_QUERY_ENCODE_SET).to_string()
313→}
314→
315→fn sdz_build_canonical_uri(bucket: &str, object_name: &str) -> String {
316→    let full_path = format!("/{}/{}", bucket, object_name);
317→    sdz_encode_path(&full_path)
318→}
319→
320→fn sdz_build_query(params: &[(String, String)]) -> String {
321→    params
322→        .iter()
323→        .map(|(k, v)| format!("{}={}", sdz_encode_query(k), sdz_encode_query(v)))
324→        .collect::<Vec<_>>()
325→        .join("&")
326→}
327→
328→fn sdz_to_jst(time: DateTime<Utc>) -> DateTime<FixedOffset> {
329→    let offset = FixedOffset::east_opt(9 * 3600).expect("valid offset");
330→    time.with_timezone(&offset)
331→}
