 1→use axum::{
 2→    extract::FromRequestParts,
 3→    http::{request::Parts, HeaderMap},
 4→};
 5→
 6→use crate::presentation::error::SdzApiError;
 7→
 8→#[derive(Debug, Clone, Copy)]
 9→pub enum SdzClientType {
10→    Ios,
11→    Android,
12→}
13→
14→#[derive(Debug, Clone)]
15→pub struct SdzClientApp {
16→    pub sdz_client: SdzClientType,
17→}
18→
19→impl SdzClientApp {
20→    pub fn is_mobile(&self) -> bool {
21→        matches!(self.sdz_client, SdzClientType::Ios | SdzClientType::Android)
22→    }
23→}
24→
25→impl<S> FromRequestParts<S> for SdzClientApp
26→where
27→    S: Send + Sync,
28→{
29→    type Rejection = SdzApiError;
30→
31→    #[allow(clippy::manual_async_fn)]
32→    fn from_request_parts(
33→        parts: &mut Parts,
34→        _state: &S,
35→    ) -> impl std::future::Future<Output = Result<Self, Self::Rejection>> + Send {
36→        async move {
37→            let client = extract_client(&parts.headers)?;
38→            Ok(SdzClientApp { sdz_client: client })
39→        }
40→    }
41→}
42→
43→fn extract_client(headers: &HeaderMap) -> Result<SdzClientType, SdzApiError> {
44→    let value = headers
45→        .get("x-sdz-client")
46→        .and_then(|v| v.to_str().ok())
47→        .map(|v| v.trim().to_lowercase())
48→        .ok_or_else(|| SdzApiError::Forbidden("mobile client required (x-sdz-client)".into()))?;
49→
50→    match value.as_str() {
51→        "ios" => Ok(SdzClientType::Ios),
52→        "android" => Ok(SdzClientType::Android),
53→        _ => Err(SdzApiError::Forbidden(
54→            "invalid client type (ios/android only)".into(),
55→        )),
56→    }
57→}
