 95→    async fn find_by_id(&self, spot_id: &str) -> Result<Option<SdzSpot>, SdzApiError> {
 96→        let Some(doc) = self.get_document(spot_id).await? else {
 97→            return Ok(None);
 98→        };
 99→
100→        Ok(Some(doc.into_spot(spot_id.to_string())))
101→    }
102→
103→    async fn list_recent(&self, _limit: usize) -> Result<Vec<SdzSpot>, SdzApiError> {
104→        let limit = _limit.min(100) as i32;
105→        let url = format!(
106→            "https://firestore.googleapis.com/v1/projects/{}/databases/(default)/documents:runQuery",
107→            self.project_id
108→        );
109→
110→        let body = json!({
111→            "structuredQuery": {
112→                "from": [{ "collectionId": "spots" }],
113→                "orderBy": [{
114→                    "field": { "fieldPath": "createdAt" },
115→                    "direction": "DESCENDING"
116→                }],
117→                "limit": limit
118→            }
119→        });
120→
121→        let resp = self
122→            .http
123→            .post(url)
124→            .bearer_auth(&self.bearer_token)
125→            .json(&body)
126→            .send()
127→            .await
128→            .map_err(|e| {
129→                tracing::error!("Firestore runQuery request error: {:?}", e);
130→                SdzApiError::Internal
131→            })?;
132→
133→        if !resp.status().is_success() {
134→            let status = resp.status();
135→            let text = resp.text().await.unwrap_or_default();
136→            tracing::error!(
137→                "Firestore runQuery unexpected status {} body: {}",
138→                status,
139→                text
140→            );
141→            return Err(SdzApiError::Internal);
142→        }
143→
144→        let rows = resp
145→            .json::<Vec<FirestoreRunQueryResponse>>()
146→            .await
147→            .map_err(|e| {
148→                tracing::error!("Failed to parse Firestore runQuery response: {:?}", e);
149→                SdzApiError::Internal
150→            })?;
151→
152→        let mut spots = Vec::new();
153→        for row in rows {
154→            if let Some(doc) = row.document {
155→                if let Some(spot_id) = extract_doc_id(&doc.name) {
156→                    spots.push(doc.into_spot(spot_id));
157→                }
158→            }
159→        }
160→        Ok(spots)
161→    }
162→}
