 22→export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
 23→  const [user, setUser] = useState(auth.currentUser);
 24→  const [idToken, setIdToken] = useState<string | null>(null);
 25→  const [loading, setLoading] = useState(true);
 26→
 27→  // users/{uid} を存在しなければ作成（createdAtのみセット、updatedAtはnull）
 28→  const ensureUserDoc = useCallback(async (uid: string, email: string | null) => {
 29→    try {
 30→      if (!email) {
 31→        throw new Error('メールアドレスが取得できませんでした。');
 32→      }
 33→      const db = getFirestore();
 34→      const docRef = doc(db, 'users', uid);
 35→      const snap = await getDoc(docRef);
 36→      if (!snap.exists()) {
 37→        await setDoc(
 38→          docRef,
 39→          {
 40→            email,
 41→            createdAt: serverTimestamp(),
 42→            updatedAt: null, // 初回はnull、更新時に上書きする想定
 43→          },
 44→          { merge: true },
 45→        );
 46→      } else {
 47→        // 既存ドキュメントでもemailが空なら補完する
 48→        const current = snap.data();
 49→        if (!current?.email) {
 50→          await setDoc(
 51→            docRef,
 52→            { email, updatedAt: serverTimestamp() },
 53→            { merge: true },
 54→          );
 55→        }
 56→      }
 57→
 58→      // 書き込み後に存在を確認し、なければエラー
 59→      const confirm = await getDoc(docRef);
 60→      if (!confirm.exists()) {
 61→        throw new Error('Firestoreにユーザードキュメントを作成できませんでした。');
 62→      }
 63→    } catch (err) {
 64→      console.error('ensureUserDoc failed', err);
 65→      throw err instanceof Error
 66→        ? err
 67→        : new Error('ユーザープロファイルの作成に失敗しました。');
 68→    }
 69→  }, []);
 70→
 71→  useEffect(() => {
 72→    const unsub = onAuthStateChanged(auth, async (nextUser) => {
 73→      setUser(nextUser);
 74→      if (nextUser) {
 75→        const token = await nextUser.getIdToken();
 76→        setIdToken(token);
 77→      } else {
 78→        setIdToken(null);
 79→      }
 80→      setLoading(false);
 81→    });
 82→    return () => unsub();
 83→  }, []);
 84→
 85→  const loginWithGoogle = useCallback(async () => {
 86→    const provider = new GoogleAuthProvider();
 87→    provider.setCustomParameters({ prompt: 'select_account' });
 88→    const credential = await signInWithPopup(auth, provider);
 89→    const user = credential.user;
 90→    const token = await user.getIdToken();
 91→    setIdToken(token ?? null);
 92→
 93→    await ensureUserDoc(user.uid, user.email);
 94→
 95→    // 初回ログイン時のFirestore作成は後続のサーバーサイド処理や別タイミングで実施する想定
 96→  }, [ensureUserDoc]);
 97→
 98→  const loginWithEmail = useCallback(async (email: string, password: string) => {
 99→    const credential = await signInWithEmailAndPassword(auth, email, password);
100→    if (!credential.user.emailVerified) {
101→      await sendEmailVerification(credential.user);
102→      setIdToken(null);
103→      throw new Error('メールアドレスが未認証です。受信トレイの認証メールを確認してください。');
104→    }
105→    await ensureUserDoc(credential.user.uid, credential.user.email);
106→    const token = await credential.user.getIdToken();
107→    setIdToken(token ?? null);
108→  }, [ensureUserDoc]);
109→
110→  const signupWithEmail = useCallback(async (email: string, password: string) => {
111→    const credential = await createUserWithEmailAndPassword(auth, email, password);
112→    const user = credential.user;
113→    await sendEmailVerification(user);
114→    // 認証完了までは保護するため、トークンはクリアしておく
115→    setIdToken(null);
116→
117→    await ensureUserDoc(user.uid, email);
118→  }, [ensureUserDoc]);
119→
120→  const logout = useCallback(async () => {
121→    await signOut(auth);
122→    setIdToken(null);
123→  }, []);
124→
125→  const resendVerification = useCallback(async () => {
126→    if (auth.currentUser && !auth.currentUser.emailVerified) {
127→      await sendEmailVerification(auth.currentUser);
128→    } else {
129→      throw new Error('再送できる未認証ユーザーが見つかりません。');
130→    }
131→  }, []);
132→
133→  const sendPasswordReset = useCallback(async () => {
134→    if (!auth.currentUser?.email) {
135→      throw new Error('再設定用のメールアドレスが見つかりません。');
136→    }
137→    await sendPasswordResetEmail(auth, auth.currentUser.email);
138→  }, []);
139→
140→  const value = useMemo(
141→    () => ({
142→      user,
143→      idToken,
144→      loading,
145→      loginWithGoogle,
146→      loginWithEmail,
147→      signupWithEmail,
148→      resendVerification,
149→      sendPasswordReset,
150→      logout,
151→    }),
152→    [
153→      user,
154→      idToken,
155→      loading,
156→      loginWithGoogle,
157→      loginWithEmail,
158→      signupWithEmail,
159→      resendVerification,
160→      sendPasswordReset,
161→      logout,
162→    ],
163→  );
164→
165→  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
166→};
