321→  }, [sdzFavorites.length]);
322→
323→  const handleLoginWithGoogle = async () => {
324→    setAuthError(null);
325→    try {
326→      await loginWithGoogle();
327→    } catch (err) {
328→      setAuthError((err as Error).message);
329→    }
330→  };
331→
332→  const handleLoginWithEmail = async (e: React.FormEvent) => {
333→    e.preventDefault();
334→    setAuthError(null);
335→    try {
336→      await loginWithEmail(loginEmail, loginPassword);
337→      setLoginEmail('');
338→      setLoginPassword('');
339→    } catch (err) {
340→      setAuthError((err as Error).message);
341→    }
342→  };
343→
344→  const handleSignupWithEmail = async (e: React.FormEvent) => {
345→    e.preventDefault();
346→    setAuthError(null);
347→    try {
348→      await signupWithEmail(loginEmail, loginPassword);
349→      setLoginEmail('');
350→      setLoginPassword('');
351→    } catch (err) {
352→      if (
353→        err &&
354→        typeof err === 'object' &&
355→        'code' in err &&
356→        (err as { code?: string }).code === 'auth/email-already-in-use'
357→      ) {
358→        setAuthError('すでに登録済みです。ログインしてください。');
359→        setSdzAuthMode('login');
360→        return;
361→      }
362→      setAuthError((err as Error).message);
