748→                      前へ
749→                    </button>
750→                    <span>
751→                      {sdzFavoritesPaging.page} / {sdzFavoritesPaging.totalPages}
752→                    </span>
753→                    <button
754→                      type="button"
755→                      className="sdz-ghost"
756→                      onClick={() =>
757→                        setSdzFavoritesPage((prev) =>
758→                          Math.min(sdzFavoritesPaging.totalPages, prev + 1),
759→                        )
760→                      }
761→                      disabled={sdzFavoritesPaging.page === sdzFavoritesPaging.totalPages}
762→                    >
763→                      次へ
764→                    </button>
765→                  </div>
766→                </>
767→              )}
768→            </div>
769→          }
770→        />
771→        <Route
772→          path="/me"
773→          element={
774→            <div className="sdz-profile-grid">
775→              <div className="sdz-card">
776→                <h2>マイページ</h2>
777→                <p className="sdz-meta">ログインしたユーザーの情報と保存内容</p>
778→                {!user ? (
779→                  <p>ログインするとマイページを利用できます。</p>
780→                ) : (
781→                  <>
782→                    <div className="sdz-profile-summary">
783→                      <div>
784→                        <strong>{user.displayName || 'ユーザー名未設定'}</strong>
785→                        <div className="sdz-meta">{user.email ?? user.uid}</div>
786→                      </div>
787→                      <div className="sdz-profile-pill">
788→                        投稿 {sdzMySpots.length}件 / お気に入り {sdzFavoriteSpots.length}件
789→                      </div>
790→                    </div>
791→                    {sdzHasPasswordProvider ? (
792→                      <button type="button" className="sdz-ghost" onClick={handlePasswordReset}>
793→                        パスワード再設定メールを送信
794→                      </button>
795→                    ) : (
796→                      <div className="sdz-meta">
797→                        Googleログインの場合はGoogleアカウント側でパスワードを変更してください。
798→                      </div>
799→                    )}
800→                    {sdzProfileMessage && <p className="sdz-meta">{sdzProfileMessage}</p>}
801→                    <button
802→                      type="button"
803→                      className="sdz-ghost"
804→                      onClick={() => navigate('/favorites')}
805→                    >
806→                      お気に入りページへ
807→                    </button>
808→                  </>
809→                )}
810→              </div>
811→              <div className="sdz-card">
812→                <h3>お気に入り</h3>
813→                {sdzFavoriteSpots.length === 0 ? (
814→                  <p className="sdz-meta">お気に入りがありません。</p>
815→                ) : (
816→                  <div className="sdz-related-list">
817→                    {sdzFavoriteSpots.map((spot) => (
818→                      <button
819→                        key={spot.spotId}
820→                        type="button"
821→                        className="sdz-related-item"
822→                        onClick={() => navigate(`/spots/${spot.spotId}`)}
823→                      >
824→                        <span>{spot.name}</span>
825→                        <span className="sdz-meta">{formatCoords(spot.location)}</span>
826→                      </button>
827→                    ))}
828→                  </div>
829→                )}
830→              </div>
831→              <div className="sdz-card">
832→                <h3>自分のスポット</h3>
833→                {sdzMySpots.length === 0 ? (
834→                  <p className="sdz-meta">まだ投稿したスポットがありません。</p>
835→                ) : (
836→                  <div className="sdz-related-list">
837→                    {sdzMySpots.map((spot) => (
838→                      <button
839→                        key={spot.spotId}
840→                        type="button"
841→                        className="sdz-related-item"
842→                        onClick={() => navigate(`/spots/${spot.spotId}`)}
843→                      >
844→                        <span>{spot.name}</span>
845→                        <span className="sdz-meta">{formatCoords(spot.location)}</span>
846→                      </button>
847→                    ))}
848→                  </div>
849→                )}
850→              </div>
851→            </div>
852→          }
853→        />
854→      </Routes>
855→    </div>
856→  );
857→}
