 29→}
 30→
 31→#[derive(Debug, Clone, Serialize, Deserialize)]
 32→pub struct SdzSpotLocation {
 33→    pub lat: f64,
 34→    pub lng: f64,
 35→}
 36→
 37→#[derive(Debug, Clone, Serialize, Deserialize)]
 38→pub struct SdzSpot {
 39→    #[serde(rename = "spotId")]
 40→    pub sdz_spot_id: String,
 41→    pub name: String,
 42→    pub description: Option<String>,
 43→    pub location: Option<SdzSpotLocation>,
 44→    pub tags: Vec<String>,
 45→    pub images: Vec<String>,
 46→    #[serde(rename = "trustLevel")]
 47→    pub sdz_trust_level: SdzSpotTrustLevel,
 48→    #[serde(rename = "trustSources")]
 49→    pub sdz_trust_sources: Vec<String>,
 50→    #[serde(rename = "userId")]
 51→    pub sdz_user_id: String,
 52→    #[serde(rename = "createdAt")]
 53→    pub created_at: DateTime<FixedOffset>,
 54→    #[serde(rename = "updatedAt")]
 55→    pub updated_at: DateTime<FixedOffset>,
 56→}
 57→
 58→#[derive(Debug, Clone, Serialize, Deserialize)]
 59→#[serde(rename_all = "lowercase")]
 60→pub enum SdzSpotTrustLevel {
 61→    Verified,
 62→    Unverified,
 63→}
 64→
 65→impl SdzSpot {
 66→    pub fn new_with_id(
 67→        sdz_spot_id: String,
 68→        name: String,
 69→        description: Option<String>,
 70→        location: Option<SdzSpotLocation>,
 71→        tags: Vec<String>,
 72→        images: Vec<String>,
 73→        sdz_user_id: String,
 74→    ) -> Result<Self, SdzSpotValidationError> {
 75→        validate_spot(&name, location.as_ref(), &tags, &images)?;
 76→        Ok(Self {
 77→            sdz_spot_id,
 78→            name,
 79→            description,
 80→            location,
 81→            tags,
 82→            images,
 83→            sdz_trust_level: SdzSpotTrustLevel::Unverified,
 84→            sdz_trust_sources: Vec::new(),
 85→            sdz_user_id,
 86→            created_at: now_jst(),
 87→            updated_at: now_jst(),
 88→        })
 89→    }
 90→}
 91→
 92→fn validate_spot(
 93→    name: &str,
 94→    location: Option<&SdzSpotLocation>,
 95→    tags: &[String],
 96→    images: &[String],
 97→) -> Result<(), SdzSpotValidationError> {
 98→    if name.trim().is_empty() {
 99→        return Err(SdzSpotValidationError::NameIsRequired);
100→    }
101→    if let Some(loc) = location {
102→        if !(loc.lat >= -90.0 && loc.lat <= 90.0) {
103→            return Err(SdzSpotValidationError::InvalidLatitude);
104→        }
105→        if !(loc.lng >= -180.0 && loc.lng <= 180.0) {
106→            return Err(SdzSpotValidationError::InvalidLongitude);
107→        }
108→    }
109→    if tags.len() > 10 {
110→        return Err(SdzSpotValidationError::TooManyTags);
111→    }
112→    if images.len() > 10 {
113→        return Err(SdzSpotValidationError::TooManyImages);
114→    }
115→    Ok(())
116→}
117→
118→fn now_jst() -> DateTime<FixedOffset> {
119→    // 日本標準時（UTC+9）でタイムスタンプを付与
120→    let offset = FixedOffset::east_opt(9 * 3600).expect("valid offset");
121→    chrono::Utc::now().with_timezone(&offset)
122→}
123→
124→#[derive(Debug, Error)]
125→pub enum SdzSpotValidationError {
126→    #[error("name is required")]
127→    NameIsRequired,
128→    #[error("lat must be between -90 and 90")]
129→    InvalidLatitude,
130→    #[error("lng must be between -180 and 180")]
131→    InvalidLongitude,
132→    #[error("tags must be <= 10 items")]
133→    TooManyTags,
134→    #[error("images must be <= 10 items")]
135→    TooManyImages,
136→}
