  1→use axum::{body::Body, http::Request, routing::get, Router};
  2→use http::{HeaderValue, Method};
  3→use std::time::Duration;
  4→use tower_http::{
  5→    cors::{AllowOrigin, CorsLayer},
  6→    request_id::{MakeRequestUuid, PropagateRequestIdLayer, SetRequestIdLayer},
  7→    trace::TraceLayer,
  8→};
  9→
 10→use std::sync::Arc;
 11→
 12→use crate::{
 13→    application::use_cases::{
 14→        spot_repository::SdzSpotRepository, storage_repository::SdzStorageRepository,
 15→        user_repository::SdzUserRepository,
 16→    },
 17→    domain::models::SdzUser,
 18→    infrastructure::{
 19→        firestore_spot_repository::SdzFirestoreSpotRepository,
 20→        firestore_user_repository::SdzFirestoreUserRepository,
 21→        in_memory_spot_repository::SdzInMemorySpotRepository,
 22→        in_memory_user_repository::SdzInMemoryUserRepository,
 23→        storage_disabled_repository::SdzDisabledStorageRepository,
 24→        storage_signed_url_repository::SdzStorageSignedUrlRepository,
 25→    },
 26→};
 27→
 28→use super::handlers::{health_handler, spot_handler, user_handler};
 29→
 30→pub fn sdz_build_router() -> Router {
 31→    let state = build_state();
 32→
 33→    Router::new()
 34→        .route("/sdz/health", get(health_handler::handle_health))
 35→        .route("/sdz/users/me", get(user_handler::handle_get_me))
 36→        .route(
 37→            "/sdz/spots",
 38→            axum::routing::post(spot_handler::handle_create_spot),
 39→        )
 40→        .route(
 41→            "/sdz/spots/upload-url",
 42→            axum::routing::post(spot_handler::handle_create_upload_url),
 43→        )
 44→        .route("/sdz/spots", get(spot_handler::handle_list_spots))
 45→        .route("/sdz/spots/{spot_id}", get(spot_handler::handle_get_spot))
 46→        .with_state(state)
 47→        .layer(PropagateRequestIdLayer::x_request_id())
 48→        .layer(SetRequestIdLayer::x_request_id(MakeRequestUuid))
 49→        .layer(cors_layer())
 50→        .layer(
 51→            TraceLayer::new_for_http()
 52→                .make_span_with(|request: &Request<Body>| {
 53→                    let request_id = request
 54→                        .extensions()
 55→                        .get::<tower_http::request_id::RequestId>()
 56→                        .and_then(|id| id.header_value().to_str().ok())
 57→                        .unwrap_or("-");
 58→                    tracing::info_span!(
 59→                        "http_request",
 60→                        event_code = "SDZ-API-1001",
 61→                        component = "presentation",
 62→                        method = %request.method(),
 63→                        uri = %request.uri(),
 64→                        request_id = %request_id
 65→                    )
 66→                })
 67→                .on_response(
 68→                    |response: &axum::response::Response,
 69→                     latency: Duration,
 70→                     span: &tracing::Span| {
 71→                        tracing::info!(
 72→                            parent: span,
 73→                            event_code = "SDZ-API-1002",
 74→                            component = "presentation",
 75→                            status = %response.status(),
 76→                            latency_ms = latency.as_millis()
 77→                        );
 78→                    },
 79→                )
 80→                .on_failure(
 81→                    |error: tower_http::classify::ServerErrorsFailureClass,
 82→                     latency: Duration,
 83→                     span: &tracing::Span| {
 84→                        tracing::error!(
 85→                            parent: span,
 86→                            event_code = "SDZ-API-1003",
 87→                            component = "presentation",
 88→                            error = %error,
 89→                            latency_ms = latency.as_millis()
 90→                        );
 91→                    },
 92→                ),
 93→        )
 94→}
 95→
 96→fn cors_layer() -> CorsLayer {
 97→    CorsLayer::new()
 98→        .allow_origin(allowed_origins())
 99→        .allow_methods([Method::GET, Method::POST, Method::PATCH, Method::DELETE])
100→        .allow_headers(tower_http::cors::Any)
101→}
102→
103→fn allowed_origins() -> AllowOrigin {
104→    // 環境変数SDZ_CORS_ALLOWED_ORIGINSにカンマ区切りで指定。
105→    // 未設定時はローカル開発用のlocalhostを許可。
106→    if let Ok(origins) = std::env::var("SDZ_CORS_ALLOWED_ORIGINS") {
107→        let list: Vec<HeaderValue> = origins
108→            .split(',')
109→            .filter_map(|s| {
110→                let trimmed = s.trim();
111→                if trimmed.is_empty() {
112→                    None
113→                } else {
114→                    HeaderValue::from_str(trimmed).ok()
115→                }
116→            })
117→            .collect();
118→        if !list.is_empty() {
119→            return AllowOrigin::list(list);
120→        }
121→    }
122→
123→    // デフォルトは開発用
124→    AllowOrigin::list(
125→        ["http://localhost:3000", "http://127.0.0.1:3000"]
126→            .iter()
127→            .filter_map(|o| HeaderValue::from_str(o).ok()),
128→    )
129→}
130→
131→fn build_state() -> SdzAppState {
132→    let storage_repo: Arc<dyn SdzStorageRepository> = build_storage_repo();
133→    // 環境変数が整っていればFirestore実装を採用
134→    if std::env::var("SDZ_USE_FIRESTORE").ok().as_deref() == Some("1") {
135→        if let (Ok(project_id), Ok(token)) = (
136→            std::env::var("SDZ_FIRESTORE_PROJECT_ID")
