 12→pub struct SdzFirestoreSpotRepository {
 13→    project_id: String,
 14→    bearer_token: String,
 15→    http: Client,
 16→}
 17→
 18→impl SdzFirestoreSpotRepository {
 19→    pub fn new(project_id: String, bearer_token: String) -> Result<Self, SdzApiError> {
 20→        let http = Client::builder().build().map_err(|e| {
 21→            tracing::error!("Failed to build reqwest client: {:?}", e);
 22→            SdzApiError::Internal
 23→        })?;
 24→        Ok(Self {
 25→            project_id,
 26→            bearer_token,
 27→            http,
 28→        })
 29→    }
 30→
 31→    async fn upsert_document(&self, spot: &SdzSpot) -> Result<(), SdzApiError> {
 32→        let url = format!(
 33→            "https://firestore.googleapis.com/v1/projects/{}/databases/(default)/documents/spots/{}",
 34→            self.project_id, spot.sdz_spot_id
 35→        );
 36→
 37→        let body = build_firestore_doc(spot)?;
 38→
 39→        let resp = self
 40→            .http
 41→            .patch(url)
 42→            .bearer_auth(&self.bearer_token)
 43→            .json(&body)
 44→            .send()
 45→            .await
 46→            .map_err(|e| {
 47→                tracing::error!("Firestore request error: {:?}", e);
 48→                SdzApiError::Internal
 49→            })?;
 50→
 51→        map_status(resp.status(), resp.text().await).map(|_| ())
 52→    }
 53→
 54→    async fn get_document(&self, spot_id: &str) -> Result<Option<FirestoreSpotDoc>, SdzApiError> {
 55→        let url = format!(
 56→            "https://firestore.googleapis.com/v1/projects/{}/databases/(default)/documents/spots/{}",
 57→            self.project_id, spot_id
 58→        );
 59→        let resp = self
 60→            .http
 61→            .get(url)
 62→            .bearer_auth(&self.bearer_token)
 63→            .send()
 64→            .await
 65→            .map_err(|e| {
 66→                tracing::error!("Firestore request error: {:?}", e);
 67→                SdzApiError::Internal
 68→            })?;
 69→
 70→        match resp.status() {
 71→            reqwest::StatusCode::OK => {
 72→                let doc = resp.json::<FirestoreSpotDoc>().await.map_err(|e| {
 73→                    tracing::error!("Failed to parse Firestore response: {:?}", e);
 74→                    SdzApiError::Internal
 75→                })?;
 76→                Ok(Some(doc))
 77→            }
 78→            reqwest::StatusCode::NOT_FOUND => Ok(None),
 79→            code => {
 80→                let body = resp.text().await.unwrap_or_default();
 81→                tracing::error!("Firestore unexpected status: {} body: {}", code, body);
 82→                Err(SdzApiError::Internal)
 83→            }
 84→        }
 85→    }
 86→}
 87→
 88→#[async_trait]
 89→impl SdzSpotRepository for SdzFirestoreSpotRepository {
 90→    async fn create(&self, spot: SdzSpot) -> Result<SdzSpot, SdzApiError> {
 91→        self.upsert_document(&spot).await?;
 92→        Ok(spot)
 93→    }
 94→
 95→    async fn find_by_id(&self, spot_id: &str) -> Result<Option<SdzSpot>, SdzApiError> {
 96→        let Some(doc) = self.get_document(spot_id).await? else {
 97→            return Ok(None);
 98→        };
 99→
100→        Ok(Some(doc.into_spot(spot_id.to_string())))
101→    }
102→
103→    async fn list_recent(&self, _limit: usize) -> Result<Vec<SdzSpot>, SdzApiError> {
104→        let limit = _limit.min(100) as i32;
105→        let url = format!(
106→            "https://firestore.googleapis.com/v1/projects/{}/databases/(default)/documents:runQuery",
107→            self.project_id
108→        );
109→
110→        let body = json!({
111→            "structuredQuery": {
112→                "from": [{ "collectionId": "spots" }],
113→                "orderBy": [{
114→                    "field": { "fieldPath": "createdAt" },
115→                    "direction": "DESCENDING"
116→                }],
117→                "limit": limit
118→            }
119→        });
120→
121→        let resp = self
122→            .http
123→            .post(url)
124→            .bearer_auth(&self.bearer_token)
125→            .json(&body)
126→            .send()
127→            .await
128→            .map_err(|e| {
129→                tracing::error!("Firestore runQuery request error: {:?}", e);
130→                SdzApiError::Internal
131→            })?;
132→
133→        if !resp.status().is_success() {
134→            let status = resp.status();
135→            let text = resp.text().await.unwrap_or_default();
136→            tracing::error!(
137→                "Firestore runQuery unexpected status {} body: {}",
138→                status,
139→                text
140→            );
141→            return Err(SdzApiError::Internal);
142→        }
143→
144→        let rows = resp
145→            .json::<Vec<FirestoreRunQueryResponse>>()
146→            .await
147→            .map_err(|e| {
148→                tracing::error!("Failed to parse Firestore runQuery response: {:?}", e);
149→                SdzApiError::Internal
150→            })?;
151→
152→        let mut spots = Vec::new();
153→        for row in rows {
154→            if let Some(doc) = row.document {
155→                if let Some(spot_id) = extract_doc_id(&doc.name) {
156→                    spots.push(doc.into_spot(spot_id));
157→                }
158→            }
159→        }
160→        Ok(spots)
161→    }
162→}
