234→impl FirestoreSpotDoc {
235→    fn into_spot(self, spot_id: String) -> SdzSpot {
236→        let fields = self.fields;
237→        let tags = fields
238→            .tags
239→            .and_then(|f| f.array_value.values)
240→            .unwrap_or_default()
241→            .into_iter()
242→            .map(|v| v.string_value)
243→            .collect();
244→        let images = fields
245→            .images
246→            .and_then(|f| f.array_value.values)
247→            .unwrap_or_default()
248→            .into_iter()
249→            .map(|v| v.string_value)
250→            .collect();
251→        let trust_sources = fields
252→            .trust_sources
253→            .and_then(|f| f.array_value.values)
254→            .unwrap_or_default()
255→            .into_iter()
256→            .map(|v| v.string_value)
257→            .collect();
258→        let location = fields.location.and_then(|loc| {
259→            let mv = loc.map_value.fields?;
260→            let lat = mv.lat?.double_value;
261→            let lng = mv.lng?.double_value;
262→            Some(SdzSpotLocation { lat, lng })
263→        });
264→        let created_at = parse_timestamp(fields.created_at.map(|t| t.timestamp_value))
265→            .unwrap_or_else(|| chrono::Utc::now().into());
266→        let updated_at = parse_timestamp(fields.updated_at.map(|t| t.timestamp_value))
267→            .unwrap_or_else(|| chrono::Utc::now().into());
268→
269→        SdzSpot {
270→            sdz_spot_id: spot_id,
271→            name: fields
272→                .name
273→                .map(|s| s.string_value)
274→                .unwrap_or_else(|| "unknown".into()),
275→            description: fields.description.map(|s| s.string_value),
276→            location,
277→            tags,
278→            images,
279→            sdz_trust_level: parse_trust_level(fields.trust_level.map(|s| s.string_value)),
280→            sdz_trust_sources: trust_sources,
281→            sdz_user_id: fields.user_id.map(|s| s.string_value).unwrap_or_default(),
282→            created_at,
283→            updated_at,
284→        }
285→    }
286→}
