288→fn build_firestore_doc(spot: &SdzSpot) -> Result<serde_json::Value, SdzApiError> {
289→    let tags_values: Vec<serde_json::Value> = spot
290→        .tags
291→        .iter()
292→        .map(|t| json!({ "stringValue": t }))
293→        .collect();
294→    let images_values: Vec<serde_json::Value> = spot
295→        .images
296→        .iter()
297→        .map(|i| json!({ "stringValue": i }))
298→        .collect();
299→
300→    let mut fields = Map::new();
301→    fields.insert("name".into(), json!({ "stringValue": spot.name.clone() }));
302→    if let Some(desc) = &spot.description {
303→        fields.insert("description".into(), json!({ "stringValue": desc }));
304→    }
305→    fields.insert(
306→        "userId".into(),
307→        json!({ "stringValue": spot.sdz_user_id.clone() }),
308→    );
309→    if !tags_values.is_empty() {
310→        fields.insert(
311→            "tags".into(),
312→            json!({ "arrayValue": { "values": tags_values } }),
313→        );
314→    }
315→    if !images_values.is_empty() {
316→        fields.insert(
317→            "images".into(),
318→            json!({ "arrayValue": { "values": images_values } }),
319→        );
320→    }
321→    fields.insert(
322→        "trustLevel".into(),
323→        json!({ "stringValue": trust_level_as_str(&spot.sdz_trust_level) }),
324→    );
325→    if !spot.sdz_trust_sources.is_empty() {
326→        let trust_values: Vec<serde_json::Value> = spot
327→            .sdz_trust_sources
328→            .iter()
329→            .map(|s| json!({ "stringValue": s }))
330→            .collect();
331→        fields.insert(
332→            "trustSources".into(),
333→            json!({ "arrayValue": { "values": trust_values } }),
334→        );
335→    }
336→    if let Some(loc) = &spot.location {
337→        fields.insert(
338→            "location".into(),
339→            json!({
340→                "mapValue": {
341→                    "fields": {
342→                        "lat": { "doubleValue": loc.lat },
343→                        "lng": { "doubleValue": loc.lng }
344→                    }
345→                }
346→            }),
347→        );
348→    }
349→    fields.insert(
350→        "createdAt".into(),
351→        json!({ "timestampValue": spot.created_at.to_rfc3339() }),
352→    );
353→    fields.insert(
354→        "updatedAt".into(),
355→        json!({ "timestampValue": spot.updated_at.to_rfc3339() }),
356→    );
357→
358→    Ok(json!({ "fields": fields }))
359→}
360→
361→fn parse_timestamp(ts: Option<String>) -> Option<chrono::DateTime<chrono::FixedOffset>> {
362→    ts.and_then(|s| chrono::DateTime::parse_from_rfc3339(&s).ok())
363→}
364→
365→fn parse_trust_level(value: Option<String>) -> SdzSpotTrustLevel {
366→    match value.as_deref() {
367→        Some("verified") => SdzSpotTrustLevel::Verified,
368→        _ => SdzSpotTrustLevel::Unverified,
369→    }
370→}
371→
372→fn trust_level_as_str(level: &SdzSpotTrustLevel) -> &'static str {
373→    match level {
374→        SdzSpotTrustLevel::Verified => "verified",
375→        SdzSpotTrustLevel::Unverified => "unverified",
376→    }
377→}
378→
379→fn map_status(
380→    status: reqwest::StatusCode,
381→    body: Result<String, reqwest::Error>,
382→) -> Result<(), SdzApiError> {
383→    match status {
384→        reqwest::StatusCode::OK | reqwest::StatusCode::CREATED => Ok(()),
385→        reqwest::StatusCode::BAD_REQUEST => {
386→            tracing::error!("Firestore returned 400: {:?}", body);
387→            Err(SdzApiError::BadRequest("invalid data for Firestore".into()))
388→        }
389→        reqwest::StatusCode::UNAUTHORIZED | reqwest::StatusCode::FORBIDDEN => {
390→            tracing::error!("Firestore returned auth error: {:?}", body);
391→            Err(SdzApiError::Unauthorized)
392→        }
393→        reqwest::StatusCode::NOT_FOUND => Err(SdzApiError::NotFound),
394→        code => {
395→            let text = body.unwrap_or_default();
396→            tracing::error!("Firestore unexpected status {} body: {}", code, text);
397→            Err(SdzApiError::Internal)
398→        }
399→    }
400→}
