  9→function formatCoords(location?: SdzSpot['location']) {
 10→  if (!location) return 'N/A';
 11→  return `${location.lat.toFixed(4)}, ${location.lng.toFixed(4)}`;
 12→}
 13→
 14→function formatDateTime(value?: string) {
 15→  if (!value) return '-';
 16→  const date = new Date(value);
 17→  if (Number.isNaN(date.getTime())) return value;
 18→  return date.toLocaleString('ja-JP', {
 19→    year: 'numeric',
 20→    month: '2-digit',
 21→    day: '2-digit',
 22→    hour: '2-digit',
 23→    minute: '2-digit',
 24→  });
 25→}
 26→
 27→function paginate<T>(items: T[], page: number, perPage: number) {
 28→  const totalPages = Math.max(1, Math.ceil(items.length / perPage));
 29→  const safePage = Math.min(Math.max(page, 1), totalPages);
 30→  const start = (safePage - 1) * perPage;
 31→  return {
 32→    page: safePage,
 33→    totalPages,
 34→    items: items.slice(start, start + perPage),
 35→  };
 36→}
