 66→  const [sdzDetailLoading, setSdzDetailLoading] = useState(false);
 67→  const [sdzDetailError, setSdzDetailError] = useState<string | null>(null);
 68→
 69→  useEffect(() => {
 70→    if (!spotId) return;
 71→    const sdzExisting = spots.find((spot) => spot.spotId === spotId);
 72→    if (sdzExisting) {
 73→      setSdzDetail(sdzExisting);
 74→      setSdzDetailError(null);
 75→      return;
 76→    }
 77→    let isActive = true;
 78→    setSdzDetailLoading(true);
 79→    setSdzDetailError(null);
 80→    fetch(`${apiUrl}/sdz/spots/${spotId}`)
 81→      .then((res) => {
 82→        if (res.status === 404) {
 83→          return null;
 84→        }
 85→        if (!res.ok) {
 86→          throw new Error(`スポットの取得に失敗しました (HTTP ${res.status})`);
 87→        }
 88→        return res.json() as Promise<SdzSpot>;
 89→      })
 90→      .then((data) => {
 91→        if (!isActive) return;
 92→        if (!data) {
 93→          setSdzDetail(null);
 94→          return;
 95→        }
 96→        setSdzDetail(data);
 97→      })
 98→      .catch((err) => {
 99→        if (!isActive) return;
100→        setSdzDetailError((err as Error).message);
101→      })
102→      .finally(() => {
103→        if (!isActive) return;
104→        setSdzDetailLoading(false);
105→      });
106→    return () => {
107→      isActive = false;
108→    };
109→  }, [apiUrl, spotId, spots]);
110→
111→  const sdzRelatedSpots = useMemo(() => {
112→    if (!sdzDetail) return [];
113→    const baseTags = new Set(sdzDetail.tags ?? []);
114→    const related = spots.filter((spot) => {
115→      if (spot.spotId === sdzDetail.spotId) return false;
116→      return spot.tags?.some((tag) => baseTags.has(tag));
117→    });
118→    return related.slice(0, 5);
119→  }, [sdzDetail, spots]);
120→
121→  if (!spotId) {
122→    return (
123→      <div className="sdz-card sdz-empty">
