 3→use serde::Deserialize;
 4→use uuid::Uuid;
 5→
 6→use crate::{
 7→    application::use_cases::storage_repository::{
 8→        SdzStorageRepository, SdzUploadUrlRequest, SdzUploadUrlResult,
 9→    },
10→    presentation::{error::SdzApiError, middleware::auth::SdzAuthUser},
11→};
12→
13→pub struct SdzGenerateUploadUrlUseCase;
14→
15→impl SdzGenerateUploadUrlUseCase {
16→    pub fn new() -> Self {
17→        Self
18→    }
19→
20→    pub async fn execute(
21→        &self,
22→        repo: Arc<dyn SdzStorageRepository>,
23→        auth_user: SdzAuthUser,
24→        input: SdzGenerateUploadUrlInput,
25→    ) -> Result<SdzUploadUrlResult, SdzApiError> {
26→        let content_type = input.sdz_content_type.trim().to_lowercase();
27→        let extension = sdz_extension_from_content_type(&content_type)
28→            .ok_or_else(|| SdzApiError::BadRequest("unsupported contentType".into()))?;
29→
30→        let object_name = format!(
31→            "spots/{}/{}.{}",
32→            auth_user.sdz_user_id,
33→            Uuid::new_v4(),
34→            extension
35→        );
36→
37→        let request = SdzUploadUrlRequest {
38→            sdz_object_name: object_name,
39→            sdz_content_type: content_type,
40→        };
41→
42→        repo.create_upload_url(request).await
43→    }
44→}
45→
46→#[derive(Debug, Clone, Deserialize)]
47→pub struct SdzGenerateUploadUrlInput {
48→    #[serde(rename = "contentType")]
49→    pub sdz_content_type: String,
50→}
51→
52→fn sdz_extension_from_content_type(content_type: &str) -> Option<&'static str> {
53→    match content_type {
54→        "image/jpeg" | "image/jpg" => Some("jpg"),
55→        "image/png" => Some("png"),
56→        "image/webp" => Some("webp"),
57→        "image/gif" => Some("gif"),
58→        "image/heic" => Some("heic"),
59→        "image/heif" => Some("heif"),
60→        _ => None,
61→    }
62→}
