103→fn allowed_origins() -> AllowOrigin {
104→    // 環境変数SDZ_CORS_ALLOWED_ORIGINSにカンマ区切りで指定。
105→    // 未設定時はローカル開発用のlocalhostを許可。
106→    if let Ok(origins) = std::env::var("SDZ_CORS_ALLOWED_ORIGINS") {
107→        let list: Vec<HeaderValue> = origins
108→            .split(',')
109→            .filter_map(|s| {
110→                let trimmed = s.trim();
111→                if trimmed.is_empty() {
112→                    None
113→                } else {
114→                    HeaderValue::from_str(trimmed).ok()
115→                }
116→            })
117→            .collect();
118→        if !list.is_empty() {
119→            return AllowOrigin::list(list);
120→        }
121→    }
122→
123→    // デフォルトは開発用
124→    AllowOrigin::list(
125→        ["http://localhost:3000", "http://127.0.0.1:3000"]
126→            .iter()
127→            .filter_map(|o| HeaderValue::from_str(o).ok()),
128→    )
129→}
