131→fn build_state() -> SdzAppState {
132→    let storage_repo: Arc<dyn SdzStorageRepository> = build_storage_repo();
133→    // 環境変数が整っていればFirestore実装を採用
134→    if std::env::var("SDZ_USE_FIRESTORE").ok().as_deref() == Some("1") {
135→        if let (Ok(project_id), Ok(token)) = (
136→            std::env::var("SDZ_FIRESTORE_PROJECT_ID")
137→                .or_else(|_| std::env::var("SDZ_AUTH_PROJECT_ID")),
138→            std::env::var("SDZ_FIRESTORE_TOKEN"),
139→        ) {
140→            if let (Ok(user_repo), Ok(spot_repo)) = (
141→                SdzFirestoreUserRepository::new(project_id.clone(), token.clone()),
142→                SdzFirestoreSpotRepository::new(project_id, token),
143→            ) {
144→                return SdzAppState {
145→                    user_repo: Arc::new(user_repo),
146→                    spot_repo: Arc::new(spot_repo),
147→                    storage_repo,
148→                };
149→            } else {
150→                tracing::warn!("Failed to init Firestore repo, falling back to in-memory");
151→            }
152→        } else {
153→            tracing::warn!(
154→                "SDZ_USE_FIRESTORE=1 but project_id/token missing. Falling back to in-memory."
155→            );
156→        }
157→    }
158→
159→    // デフォルト: ローカル動作用のメモリリポジトリ
160→    let seed_user = SdzUser {
161→        sdz_user_id: "zjJuiae1ymc6kqjU88yFsJvAuxG2".to_string(),
162→        sdz_display_name: "sdz-demo-user".to_string(),
163→        sdz_email: Some("uechi@321dev.org".to_string()),
164→    };
165→    let repo = SdzInMemoryUserRepository::new_with_seed(vec![seed_user]);
166→    SdzAppState {
167→        user_repo: Arc::new(repo),
168→        spot_repo: Arc::new(SdzInMemorySpotRepository::default()),
169→        storage_repo,
170→    }
171→}
172→
173→#[derive(Clone)]
174→pub struct SdzAppState {
175→    pub user_repo: Arc<dyn SdzUserRepository>,
176→    pub spot_repo: Arc<dyn SdzSpotRepository>,
177→    pub storage_repo: Arc<dyn SdzStorageRepository>,
178→}
179→
180→fn build_storage_repo() -> Arc<dyn SdzStorageRepository> {
181→    let bucket = std::env::var("SDZ_STORAGE_BUCKET").ok();
182→    let service_account = std::env::var("SDZ_STORAGE_SERVICE_ACCOUNT_EMAIL").ok();
183→    let expires = std::env::var("SDZ_STORAGE_SIGNED_URL_EXPIRES_SECS")
184→        .ok()
185→        .and_then(|v| v.parse::<u32>().ok())
186→        .unwrap_or(900);
187→
188→    if let (Some(bucket), Some(service_account)) = (bucket, service_account) {
189→        match SdzStorageSignedUrlRepository::new(bucket, service_account, expires) {
190→            Ok(repo) => return Arc::new(repo),
191→            Err(_) => tracing::warn!("Failed to init storage repo, falling back to disabled"),
192→        }
193→    } else {
194→        tracing::warn!("Storage config missing, upload-url will be disabled");
195→    }
196→
