134→  }
135→
136→  if (sdzDetailError) {
137→    return (
138→      <div className="sdz-error">
139→        詳細取得エラー: {sdzDetailError}
140→        <div style={{ marginTop: 8 }}>
141→          <button type="button" onClick={() => navigate('/')}>
142→            一覧へ戻る
143→          </button>
144→        </div>
145→      </div>
146→    );
147→  }
148→
149→  if (!sdzDetail) {
150→    return (
151→      <div className="sdz-card sdz-empty">
152→        <p>該当するスポットが見つかりませんでした。</p>
153→        <button type="button" onClick={() => navigate('/')}>
154→          一覧へ戻る
155→        </button>
156→      </div>
157→    );
158→  }
159→
160→  return (
161→    <div className="sdz-detail-layout">
162→      <div className="sdz-card sdz-detail">
