241→function App() {
242→  const {
243→    user,
244→    loginWithGoogle,
245→    loginWithEmail,
246→    signupWithEmail,
247→    resendVerification,
248→    logout,
249→    loading: authLoading,
250→    sendPasswordReset,
251→  } = useAuth();
252→  const [spots, setSpots] = useState<SdzSpot[]>([]);
253→  const [loading, setLoading] = useState(true);
254→  const [error, setError] = useState<string | null>(null);
255→  const [authError, setAuthError] = useState<string | null>(null);
256→  const [loginEmail, setLoginEmail] = useState('');
257→  const [loginPassword, setLoginPassword] = useState('');
258→  const [sdzAuthMode, setSdzAuthMode] = useState<'login' | 'signup'>('login');
259→  const [sdzSearchText, setSdzSearchText] = useState('');
260→  const [sdzSelectedTag, setSdzSelectedTag] = useState('all');
261→  const [sdzFavorites, setSdzFavorites] = useState<string[]>(getInitialFavorites);
262→  const [sdzProfileMessage, setSdzProfileMessage] = useState<string | null>(null);
263→  const [sdzFavoritesPage, setSdzFavoritesPage] = useState(1);
264→
265→  const subtitle = `API base: ${apiUrl}（GET /sdz/spots を表示中）`;
266→  const isEmailPending = user && !user.emailVerified;
267→  const sdzAvailableTags = useMemo(() => {
268→    const tagSet = new Set<string>();
269→    spots.forEach((spot) => {
270→      spot.tags?.forEach((tag) => tagSet.add(tag));
271→    });
272→    return Array.from(tagSet).sort((a, b) => a.localeCompare(b));
273→  }, [spots]);
274→  const sdzFilteredSpots = useMemo(() => {
275→    const normalizedQuery = sdzSearchText.trim().toLowerCase();
276→    return spots.filter((spot) => {
277→      if (sdzSelectedTag !== 'all' && !spot.tags?.includes(sdzSelectedTag)) {
278→        return false;
279→      }
280→      if (!normalizedQuery) return true;
281→      const nameMatch = spot.name.toLowerCase().includes(normalizedQuery);
282→      const descMatch = spot.description
283→        ? spot.description.toLowerCase().includes(normalizedQuery)
284→        : false;
285→      const tagMatch = spot.tags?.some((tag) =>
286→        tag.toLowerCase().includes(normalizedQuery),
287→      );
288→      return nameMatch || descMatch || tagMatch;
289→    });
290→  }, [spots, sdzSearchText, sdzSelectedTag]);
291→
292→  const fetchSpots = async (signal?: AbortSignal) => {
293→    try {
294→      const res = await fetch(`${apiUrl}/sdz/spots`, { signal });
295→      if (!res.ok) {
296→        throw new Error(`Failed to fetch spots: ${res.status}`);
297→      }
298→      const data: SdzSpot[] = await res.json();
299→      setSpots(data);
