361→fn parse_timestamp(ts: Option<String>) -> Option<chrono::DateTime<chrono::FixedOffset>> {
362→    ts.and_then(|s| chrono::DateTime::parse_from_rfc3339(&s).ok())
363→}
364→
365→fn parse_trust_level(value: Option<String>) -> SdzSpotTrustLevel {
366→    match value.as_deref() {
367→        Some("verified") => SdzSpotTrustLevel::Verified,
368→        _ => SdzSpotTrustLevel::Unverified,
369→    }
370→}
371→
372→fn trust_level_as_str(level: &SdzSpotTrustLevel) -> &'static str {
373→    match level {
374→        SdzSpotTrustLevel::Verified => "verified",
375→        SdzSpotTrustLevel::Unverified => "unverified",
376→    }
377→}
