    fn into_spot(self, spot_id: String) -> SdzSpot {
        let fields = self.fields;
        let tags = fields
            .tags
            .and_then(|f| f.array_value.values)
            .unwrap_or_default()
            .into_iter()
            .map(|v| v.string_value)
            .collect();
        let images = fields
            .images
            .and_then(|f| f.array_value.values)
            .unwrap_or_default()
            .into_iter()
