impl FirestoreSpotDoc {
    fn into_spot(self, spot_id: String) -> SdzSpot {
        let fields = self.fields;
        let tags = fields
            .tags
            .and_then(|f| f.array_value.values)
            .unwrap_or_default()
            .into_iter()
            .map(|v| v.string_value)
            .collect();
        let images = fields
            .images
            .and_then(|f| f.array_value.values)
            .unwrap_or_default()
            .into_iter()
            .map(|v| v.string_value)
            .collect();
        let trust_sources = fields
            .trust_sources
            .and_then(|f| f.array_value.values)
            .unwrap_or_default()
            .into_iter()
            .map(|v| v.string_value)
            .collect();
        let location = fields.location.and_then(|loc| {
            let mv = loc.map_value.fields?;
            let lat = mv.lat?.double_value;
            let lng = mv.lng?.double_value;
            Some(SdzSpotLocation { lat, lng })
        });
        let created_at = parse_timestamp(fields.created_at.map(|t| t.timestamp_value))
            .unwrap_or_else(|| chrono::Utc::now().into());
        let updated_at = parse_timestamp(fields.updated_at.map(|t| t.timestamp_value))
            .unwrap_or_else(|| chrono::Utc::now().into());

        let sections = fields
            .sections
            .and_then(|f| f.array_value.values)
            .unwrap_or_default()
            .into_iter()
            .map(|v| v.string_value)
            .collect();

        SdzSpot {
            sdz_spot_id: spot_id,
            name: fields
                .name
                .map(|s| s.string_value)
                .unwrap_or_else(|| "unknown".into()),
            description: fields.description.map(|s| s.string_value),
            location,
            tags,
            images,
            sdz_trust_level: parse_trust_level(fields.trust_level.map(|s| s.string_value)),
            sdz_trust_sources: trust_sources,
            sdz_spot_type: parse_spot_type(fields.spot_type.map(|s| s.string_value)),
            sdz_instagram_url: fields.instagram_url.map(|s| s.string_value),
            sdz_official_url: fields.official_url.map(|s| s.string_value),
            sdz_business_hours: fields.business_hours.map(|s| s.string_value),
            sdz_sections: sections,
            sdz_user_id: fields.user_id.map(|s| s.string_value).unwrap_or_default(),
            created_at,
            updated_at,
        }
    }
}

fn build_firestore_doc(spot: &SdzSpot) -> Result<serde_json::Value, SdzApiError> {
    let tags_values: Vec<serde_json::Value> = spot
        .tags
        .iter()
        .map(|t| json!({ "stringValue": t }))
        .collect();
    let images_values: Vec<serde_json::Value> = spot
        .images
        .iter()
        .map(|i| json!({ "stringValue": i }))
        .collect();

    let mut fields = Map::new();
    fields.insert("name".into(), json!({ "stringValue": spot.name.clone() }));
    if let Some(desc) = &spot.description {
        fields.insert("description".into(), json!({ "stringValue": desc }));
    }
    fields.insert(
        "userId".into(),
        json!({ "stringValue": spot.sdz_user_id.clone() }),
    );
    if !tags_values.is_empty() {
        fields.insert(
            "tags".into(),
            json!({ "arrayValue": { "values": tags_values } }),
        );
    }
    if !images_values.is_empty() {
        fields.insert(
            "images".into(),
            json!({ "arrayValue": { "values": images_values } }),
        );
    }
    fields.insert(
        "trustLevel".into(),
        json!({ "stringValue": trust_level_as_str(&spot.sdz_trust_level) }),
    );
    if !spot.sdz_trust_sources.is_empty() {
        let trust_values: Vec<serde_json::Value> = spot
            .sdz_trust_sources
            .iter()
            .map(|s| json!({ "stringValue": s }))
            .collect();
        fields.insert(
            "trustSources".into(),
            json!({ "arrayValue": { "values": trust_values } }),
        );
    }
    if let Some(loc) = &spot.location {
        fields.insert(
            "location".into(),
            json!({
                "mapValue": {
                    "fields": {
                        "lat": { "doubleValue": loc.lat },
                        "lng": { "doubleValue": loc.lng }
                    }
                }
            }),
        );
    }
    if let Some(spot_type) = &spot.sdz_spot_type {
        fields.insert(
            "spotType".into(),
            json!({ "stringValue": spot_type_as_str(spot_type) }),
        );
    }
    if let Some(url) = &spot.sdz_instagram_url {
        fields.insert(
            "instagramUrl".into(),
            json!({ "stringValue": url }),
        );
    }
    if let Some(url) = &spot.sdz_official_url {
        fields.insert(
            "officialUrl".into(),
            json!({ "stringValue": url }),
        );
    }
    if let Some(hours) = &spot.sdz_business_hours {
        fields.insert(
            "businessHours".into(),
            json!({ "stringValue": hours }),
        );
    }
    if !spot.sdz_sections.is_empty() {
        let sections_values: Vec<serde_json::Value> = spot
            .sdz_sections
            .iter()
            .map(|s| json!({ "stringValue": s }))
            .collect();
        fields.insert(
            "sections".into(),
            json!({ "arrayValue": { "values": sections_values } }),
        );
    }
    fields.insert(
        "createdAt".into(),
        json!({ "timestampValue": spot.created_at.to_rfc3339() }),
    );
    fields.insert(
        "updatedAt".into(),
        json!({ "timestampValue": spot.updated_at.to_rfc3339() }),
    );

    Ok(json!({ "fields": fields }))
}

fn parse_timestamp(ts: Option<String>) -> Option<chrono::DateTime<chrono::FixedOffset>> {
