            "street" => Some(SdzSpotType::Street),
            _ => None,
        });

    let spot = SdzSpot::new_admin(
        uuid::Uuid::new_v4().to_string(),
        payload.name,
        payload.description,
        payload.location.map(|loc| SdzSpotLocation {
            lat: loc.lat,
            lng: loc.lng,
        }),
        payload.tags.unwrap_or_default(),
        payload.images.unwrap_or_default(),
        admin_user.sdz_user_id,
        spot_type,
        payload.instagram_url,
        payload.official_url,
        payload.business_hours,
        payload.sections.unwrap_or_default(),
    )
    .map_err(|e| SdzApiError::BadRequest(e.to_string()))?;

    let created = state.spot_repo.create(spot).await?;

    tracing::info!(
        event_code = "SDZ-API-3002",
        component = "presentation",
        spot_id = %created.sdz_spot_id,
        "admin spot created"
    );
    Ok::<_, SdzApiError>((StatusCode::OK, Json(created)))
}

