    let use_case = SdzCreateSpotUseCase::new();
    let spot = use_case
        .execute(state.spot_repo.clone(), auth_user, payload)
        .await?;
    tracing::info!(
        event_code = "SDZ-API-2002",
        component = "presentation",
        spot_id = %spot.sdz_spot_id,
