import type { SdzSpot } from '../types/spot';

const sdzApiUrl = import.meta.env.VITE_SDZ_API_URL || 'http://localhost:8080';

export interface SdzAdminCreateSpotInput {
  name: string;
  description?: string;
  location?: { lat: number; lng: number };
  tags?: string[];
  images?: string[];
  spotType?: string;
  instagramUrl?: string;
  officialUrl?: string;
  businessHours?: string;
  sections?: string[];
}

export interface SdzAdminUpdateSpotInput {
  name?: string;
  description?: string;
  location?: { lat: number; lng: number };
  tags?: string[];
  images?: string[];
  spotType?: string;
  instagramUrl?: string;
  officialUrl?: string;
  businessHours?: string;
  sections?: string[];
}

export interface SdzUploadUrlResult {
  uploadUrl: string;
  objectUrl: string;
  objectName: string;
  expiresAt: string;
}

async function sdzAdminFetch<T>(
  path: string,
  idToken: string,
  options: RequestInit = {},
): Promise<T> {
  const res = await fetch(`${sdzApiUrl}${path}`, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${idToken}`,
      ...options.headers,
    },
  });
  if (!res.ok) {
    const body = await res.text().catch(() => '');
    throw new Error(`API error ${res.status}: ${body}`);
  }
  return res.json() as Promise<T>;
}

export function sdzAdminCreateSpot(
  idToken: string,
  input: SdzAdminCreateSpotInput,
): Promise<SdzSpot> {
  return sdzAdminFetch('/sdz/admin/spots', idToken, {
    method: 'POST',
    body: JSON.stringify(input),
  });
}

export function sdzAdminUpdateSpot(
  idToken: string,
  spotId: string,
  input: SdzAdminUpdateSpotInput,
): Promise<SdzSpot> {
  return sdzAdminFetch(`/sdz/admin/spots/${spotId}`, idToken, {
    method: 'PATCH',
    body: JSON.stringify(input),
  });
}

export function sdzAdminGetUploadUrl(
  idToken: string,
  contentType: string,
): Promise<SdzUploadUrlResult> {
  return sdzAdminFetch('/sdz/admin/spots/upload-url', idToken, {
    method: 'POST',
    body: JSON.stringify({ contentType }),
  });
}

export async function sdzAdminUploadImage(
  uploadUrl: string,
  file: File,
): Promise<void> {
  const res = await fetch(uploadUrl, {
    method: 'PUT',
    headers: { 'Content-Type': file.type },
    body: file,
  });
  if (!res.ok) {
    throw new Error(`Upload failed: ${res.status}`);
  }
}

