import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import type { SdzSpot } from '../types/spot';

const sdzApiUrl = import.meta.env.VITE_SDZ_API_URL || 'http://localhost:8080';

export function SdzAdminSpotList() {
  const navigate = useNavigate();
  const [spots, setSpots] = useState<SdzSpot[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const controller = new AbortController();
    fetch(`${sdzApiUrl}/sdz/spots`, { signal: controller.signal })
      .then((res) => {
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.json() as Promise<SdzSpot[]>;
      })
      .then(setSpots)
      .catch((err) => {
        if (err instanceof Error && err.name === 'AbortError') return;
        setError((err as Error).message);
      })
      .finally(() => setLoading(false));
    return () => controller.abort();
  }, []);

  return (
    <div className="sdz-card">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
        <h3>スポット一覧 ({spots.length}件)</h3>
        <button type="button" onClick={() => navigate('/admin/spots/new')}>
          新規作成
        </button>
      </div>

      {loading && <p>読み込み中...</p>}
      {error && <p className="sdz-error">エラー: {error}</p>}

      {!loading && !error && spots.length === 0 && (
        <p className="sdz-meta">スポットがまだありません。</p>
      )}

      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead>
          <tr>
            <th style={{ textAlign: 'left', padding: '8px 4px', borderBottom: '1px solid #333' }}>名前</th>
            <th style={{ textAlign: 'left', padding: '8px 4px', borderBottom: '1px solid #333' }}>タイプ</th>
            <th style={{ textAlign: 'left', padding: '8px 4px', borderBottom: '1px solid #333' }}>信頼度</th>
            <th style={{ textAlign: 'right', padding: '8px 4px', borderBottom: '1px solid #333' }}>操作</th>
          </tr>
        </thead>
        <tbody>
          {spots.map((spot) => (
            <tr key={spot.spotId}>
              <td style={{ padding: '8px 4px', borderBottom: '1px solid #222' }}>{spot.name}</td>
              <td style={{ padding: '8px 4px', borderBottom: '1px solid #222' }}>{spot.spotType ?? '-'}</td>
              <td style={{ padding: '8px 4px', borderBottom: '1px solid #222' }}>{spot.trustLevel}</td>
              <td style={{ padding: '8px 4px', borderBottom: '1px solid #222', textAlign: 'right' }}>
                <button
                  type="button"
                  className="sdz-ghost"
                  onClick={() => navigate(`/admin/spots/${spot.spotId}/edit`)}
                >
                  編集
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

