              style={{ width: '100%' }}
            />
          </div>

          <div>
            <label htmlFor="sdz-business-hours">営業時間</label>
            <input
              id="sdz-business-hours"
              type="text"
              value={sdzBusinessHours}
              onChange={(e) => setSdzBusinessHours(e.target.value)}
              placeholder="平日 9:00-21:00 / 土日 8:00-22:00"
