          <div>
            <label>画像 ({sdzImages.length}/10)</label>
            {sdzImages.length > 0 && (
              <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', marginBottom: 8 }}>
                {sdzImages.map((url, i) => (
                  <div key={url} style={{ position: 'relative' }}>
