import type { ReactNode } from 'react';
import { useAuth } from '../contexts/useAuth';

const SDZ_ADMIN_UIDS = (import.meta.env.VITE_SDZ_ADMIN_UIDS || '')
  .split(',')
  .map((uid: string) => uid.trim())
  .filter(Boolean);

export function sdzIsAdmin(uid: string | undefined): boolean {
  return uid != null && SDZ_ADMIN_UIDS.includes(uid);
}

export function SdzAdminGuard({ children }: { children: ReactNode }) {
  const { user, loading } = useAuth();

  if (loading) {
    return <p>認証状態を確認中...</p>;
  }

  if (!user) {
    return (
      <div className="sdz-card">
        <h2>管理画面</h2>
        <p>ログインが必要です。</p>
      </div>
    );
  }

  if (!sdzIsAdmin(user.uid)) {
    return (
      <div className="sdz-card">
        <h2>アクセス権がありません</h2>
        <p>この画面は管理者のみ利用できます。</p>
      </div>
    );
  }

  return <>{children}</>;
}

