import { useCallback, useEffect, useMemo, useState } from 'react';
import { MapContainer, TileLayer, Marker, useMapEvents, useMap } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';

// Leaflet デフォルトアイコンの修正（webpack/vite環境で壊れる問題）
const sdzDefaultIcon = L.icon({
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
  iconSize: [25, 41],
  iconAnchor: [12, 41],
  popupAnchor: [1, -34],
  shadowSize: [41, 41],
});

const SDZ_DEFAULT_CENTER: [number, number] = [35.6812, 139.7671]; // 東京駅
const SDZ_DEFAULT_ZOOM = 12;

type SdzAdminMapPickerProps = {
  lat: string;
  lng: string;
  onLocationChange: (lat: string, lng: string) => void;
};

function SdzMapClickHandler({
  onLocationChange,
}: {
  onLocationChange: (lat: number, lng: number) => void;
}) {
  useMapEvents({
    click(e) {
      onLocationChange(e.latlng.lat, e.latlng.lng);
    },
  });
  return null;
}

function SdzMapCenterUpdater({ lat, lng }: { lat: number; lng: number }) {
  const map = useMap();
  useEffect(() => {
    if (lat && lng) {
      map.setView([lat, lng], map.getZoom());
    }
  }, [lat, lng, map]);
  return null;
}

export function SdzAdminMapPicker({ lat, lng, onLocationChange }: SdzAdminMapPickerProps) {
  const [sdzSearchQuery, setSdzSearchQuery] = useState('');
  const [sdzSearching, setSdzSearching] = useState(false);

  const parsedLat = parseFloat(lat);
  const parsedLng = parseFloat(lng);
  const hasPosition = !isNaN(parsedLat) && !isNaN(parsedLng);

  const center: [number, number] = hasPosition
    ? [parsedLat, parsedLng]
    : SDZ_DEFAULT_CENTER;

  const markerPosition = useMemo(
    () => (hasPosition ? new L.LatLng(parsedLat, parsedLng) : null),
    [hasPosition, parsedLat, parsedLng],
  );

  const handleMapClick = useCallback(
    (lat: number, lng: number) => {
      onLocationChange(lat.toFixed(6), lng.toFixed(6));
    },
    [onLocationChange],
  );

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!sdzSearchQuery.trim()) return;

    setSdzSearching(true);
    try {
      // Nominatim（OpenStreetMap）で住所検索
      const res = await fetch(
        `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(sdzSearchQuery)}&limit=1&countrycodes=jp`,
        { headers: { 'Accept-Language': 'ja' } },
      );
      const data = await res.json();
      if (data.length > 0) {
        const result = data[0];
        onLocationChange(parseFloat(result.lat).toFixed(6), parseFloat(result.lon).toFixed(6));
      }
    } catch {
      // 検索失敗は無視
    } finally {
      setSdzSearching(false);
    }
  };

  return (
    <div>
      <form onSubmit={handleSearch} style={{ display: 'flex', gap: 8, marginBottom: 8 }}>
        <input
          type="text"
          value={sdzSearchQuery}
          onChange={(e) => setSdzSearchQuery(e.target.value)}
          placeholder="住所・場所名で検索（例: 駒沢オリンピック公園）"
          style={{ flex: 1 }}
        />
        <button type="submit" disabled={sdzSearching}>
          {sdzSearching ? '検索中...' : '検索'}
        </button>
      </form>

      <div style={{ height: 400, borderRadius: 4, overflow: 'hidden', marginBottom: 8 }}>
        <MapContainer
          center={center}
          zoom={SDZ_DEFAULT_ZOOM}
          style={{ height: '100%', width: '100%' }}
        >
          <TileLayer
            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          />
          <SdzMapClickHandler onLocationChange={handleMapClick} />
          {hasPosition && <SdzMapCenterUpdater lat={parsedLat} lng={parsedLng} />}
          {markerPosition && <Marker position={markerPosition} icon={sdzDefaultIcon} />}
        </MapContainer>
      </div>

      <p className="sdz-meta">地図をクリックして位置を選択、または住所検索で移動できます</p>
    </div>
  );
}

