import { useCallback, useEffect, useMemo, useState } from 'react';
import { MapContainer, TileLayer, Marker, useMapEvents, useMap } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';

// Leaflet デフォルトアイコンの修正（webpack/vite環境で壊れる問題）
const sdzDefaultIcon = L.icon({
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
  iconSize: [25, 41],
  iconAnchor: [12, 41],
  popupAnchor: [1, -34],
  shadowSize: [41, 41],
});

const SDZ_DEFAULT_CENTER: [number, number] = [35.6812, 139.7671]; // 東京駅
const SDZ_DEFAULT_ZOOM = 12;

type SdzAdminMapPickerProps = {
  lat: string;
  lng: string;
  onLocationChange: (lat: string, lng: string) => void;
};

function SdzMapClickHandler({
  onLocationChange,
}: {
  onLocationChange: (lat: number, lng: number) => void;
}) {
