import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { MapContainer, TileLayer, Marker, useMapEvents, useMap } from 'react-leaflet';
import L from 'leaflet';
import { Loader } from '@googlemaps/js-api-loader';
import 'leaflet/dist/leaflet.css';

// Leaflet デフォルトアイコンの修正（webpack/vite環境で壊れる問題）
const sdzDefaultIcon = L.icon({
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
  iconSize: [25, 41],
  iconAnchor: [12, 41],
  popupAnchor: [1, -34],
  shadowSize: [41, 41],
});

const SDZ_DEFAULT_CENTER: [number, number] = [35.6812, 139.7671]; // 東京駅
const SDZ_DEFAULT_ZOOM = 12;
const SDZ_GOOGLE_MAPS_API_KEY = import.meta.env.VITE_GOOGLE_MAPS_API_KEY || '';

type SdzAdminMapPickerProps = {
  lat: string;
  lng: string;
  onLocationChange: (lat: string, lng: string) => void;
};

function SdzMapClickHandler({
  onLocationChange,
}: {
  onLocationChange: (lat: number, lng: number) => void;
}) {
  useMapEvents({
    click(e) {
      onLocationChange(e.latlng.lat, e.latlng.lng);
    },
  });
  return null;
}

function SdzMapCenterUpdater({ lat, lng }: { lat: number; lng: number }) {
  const map = useMap();
  useEffect(() => {
    if (lat && lng) {
      map.setView([lat, lng], map.getZoom());
    }
  }, [lat, lng, map]);
  return null;
}

export function SdzAdminMapPicker({ lat, lng, onLocationChange }: SdzAdminMapPickerProps) {
  const searchInputRef = useRef<HTMLInputElement>(null);
  const autocompleteRef = useRef<google.maps.places.Autocomplete | null>(null);
  const [sdzGoogleLoaded, setSdzGoogleLoaded] = useState(false);
  const [sdzSearchError, setSdzSearchError] = useState<string | null>(null);

  const parsedLat = parseFloat(lat);
  const parsedLng = parseFloat(lng);
  const hasPosition = !isNaN(parsedLat) && !isNaN(parsedLng);

  const center: [number, number] = hasPosition
    ? [parsedLat, parsedLng]
    : SDZ_DEFAULT_CENTER;

  const markerPosition = useMemo(
    () => (hasPosition ? new L.LatLng(parsedLat, parsedLng) : null),
    [hasPosition, parsedLat, parsedLng],
  );

  const handleMapClick = useCallback(
    (clickLat: number, clickLng: number) => {
      onLocationChange(clickLat.toFixed(6), clickLng.toFixed(6));
    },
    [onLocationChange],
  );

  // Google Maps API ロード + Places Autocomplete 初期化
  useEffect(() => {
    if (!SDZ_GOOGLE_MAPS_API_KEY) {
      setSdzSearchError('VITE_GOOGLE_MAPS_API_KEY が未設定です');
      return;
    }

    const loader = new Loader({
      apiKey: SDZ_GOOGLE_MAPS_API_KEY,
      version: 'weekly',
      libraries: ['places'],
      language: 'ja',
      region: 'JP',
    });

    loader
      .importLibrary('places')
      .then(() => {
        setSdzGoogleLoaded(true);
      })
      .catch(() => {
        setSdzSearchError('Google Maps API の読み込みに失敗しました');
      });
  }, []);

  // Autocomplete をインプットに紐付け
  useEffect(() => {
    if (!sdzGoogleLoaded || !searchInputRef.current || autocompleteRef.current) return;

    const autocomplete = new google.maps.places.Autocomplete(searchInputRef.current, {
      types: ['establishment', 'geocode'],
      componentRestrictions: { country: 'jp' },
      fields: ['geometry', 'name', 'formatted_address'],
    });

    autocomplete.addListener('place_changed', () => {
      const place = autocomplete.getPlace();
      if (place.geometry?.location) {
        const placeLat = place.geometry.location.lat();
        const placeLng = place.geometry.location.lng();
        onLocationChange(placeLat.toFixed(6), placeLng.toFixed(6));
      }
    });

    autocompleteRef.current = autocomplete;
  }, [sdzGoogleLoaded, onLocationChange]);

  return (
    <div>
      <div style={{ marginBottom: 8 }}>
        <input
          ref={searchInputRef}
          type="text"
          placeholder="場所名・住所で検索（例: 駒沢公園 スケートパーク）"
          style={{ width: '100%' }}
          disabled={!sdzGoogleLoaded && !sdzSearchError}
        />
        {sdzSearchError && (
          <p className="sdz-meta" style={{ color: '#e53935', marginTop: 4 }}>{sdzSearchError}</p>
        )}
      </div>

      <div style={{ height: 400, borderRadius: 4, overflow: 'hidden', marginBottom: 8 }}>
        <MapContainer
          center={center}
          zoom={SDZ_DEFAULT_ZOOM}
          style={{ height: '100%', width: '100%' }}
        >
          <TileLayer
            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          />
          <SdzMapClickHandler onLocationChange={handleMapClick} />
          {hasPosition && <SdzMapCenterUpdater lat={parsedLat} lng={parsedLng} />}
          {markerPosition && <Marker position={markerPosition} icon={sdzDefaultIcon} />}
        </MapContainer>
      </div>

      <p className="sdz-meta">場所名を入力して候補から選択、または地図を直接クリックして位置を指定できます</p>
    </div>
  );
}

